#phone-carousel {
  perspective: 1200px;
  transform-style: preserve-3d;
  overflow: visible;
  min-height: 50vh;
  touch-action: pan-y;
}
@media (min-width: 480px)  { #phone-carousel { min-height: 55vh; } }
@media (min-width: 640px)  { #phone-carousel { min-height: 55vh; } }
@media (min-width: 1024px) { #phone-carousel { min-height: 60vh; } }

.phone-item {
  position: absolute;
  left: 50%;
  top: 50%;
  transform-origin: center center;
  will-change: transform, opacity;
}

.phone-item img {
  width: 15rem;              /* mobile default = 240px, so scale 1.0 = 240px */
  height: auto;
  border: 3px solid #1d1d1f;
  border-radius: 1.75rem;
  background: #000;
  box-shadow:
    inset 0 0 0 1px rgba(255, 255, 255, 0.08),
    0 0 0 1px rgba(0, 0, 0, 0.35);
  image-rendering: -webkit-optimize-contrast;
  backface-visibility: hidden;
  transform: translateZ(0);
  filter:
    contrast(1.04)
    saturate(1.05)
    drop-shadow(0 25px 25px rgba(0, 0, 0, 0.15));
}


@media (min-width: 640px) {
  .phone-item img {
    width: 14rem;
    border-width: 4px;
    border-radius: 2.25rem;
  }
}
@media (min-width: 1024px) {
  .phone-item img {
    width: 18rem;
    border-width: 5px;
    border-radius: 2.75rem;
  }
}


/* Dots indicator */
#carousel-dots {
  display: flex;
  gap: 0.5rem;
  justify-content: center;
  margin-top: 1rem;
}
.carousel-dot {
  width: 0.5rem;
  height: 0.5rem;
  border-radius: 9999px;
  background: #d1d5db;
  border: 0;
  padding: 0;
  transition: background 200ms, transform 200ms;
  cursor: pointer;
}
.carousel-dot.active {
  background: var(--color-primary, #10b981);
  transform: scale(1.3);
}

@media (prefers-reduced-motion: reduce) {
  .phone-item {
    transition: none !important;
  }
}
